const fs = require('fs');
const parts = [];
const enc = (s) => Buffer.from(s, 'utf8');

const p = (s) => { parts.push(enc(s)); };

p('%PDF-1.4\n');
const off1 = parts.reduce((a, b) => a + b.length, 0);

p('1 0 obj\n<</Type /Catalog /Pages 2 0 R>>\nendobj\n');
const off2 = parts.reduce((a, b) => a + b.length, 0);

p('2 0 obj\n<</Type /Pages /Kids [3 0 R] /Count 1>>\nendobj\n');
const off3 = parts.reduce((a, b) => a + b.length, 0);

p('3 0 obj\n<</Type /Page /Parent 2 0 R /MediaBox [0 0 612 792]>>\nendobj\n');
const xrefOff = parts.reduce((a, b) => a + b.length, 0);

p('xref\n0 4\n');
p('0000000000 65535 f \n');
p(String(off1).padStart(10,'0') + ' 00000 n \n');
p(String(off2).padStart(10,'0') + ' 00000 n \n');
p(String(off3).padStart(10,'0') + ' 00000 n \n');
p('trailer\n<</Size 4 /Root 1 0 R>>\nstartxref\n');
p(String(xrefOff) + '\n%%EOF\n');

fs.mkdirSync('public', { recursive: true });
fs.writeFileSync('public/sample.pdf', Buffer.concat(parts));
console.log('Written', Buffer.concat(parts).length, 'bytes');
"

